import React, { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Map, Marker } from 'pigeon-maps';
import {
  fetchRental,
  fetchRatingForRental,
  postRating,
  searchRentals,
} from '../utils/api';
import { useAuth } from '../context/AuthContext';
import StarRating from '../components/StarRating';
import { LoadingState, ErrorState } from '../components/LoadingState';

const formatPrice = (p) => (p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—');

const DetailRow = ({ label, value }) => {
  if (value == null || value === '') return null;
  return (
    <div className="detail-row">
      <span className="detail-row__label">{label}</span>
      <span className="detail-row__value">{value}</span>
    </div>
  );
};

const RentalDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [rental, setRental] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const [myRating, setMyRating] = useState(0);
  const [avgRating, setAvgRating] = useState(null);
  const [ratingLoading, setRatingLoading] = useState(false);
  const [ratingMsg, setRatingMsg] = useState('');

  const [nearby, setNearby] = useState([]);

  // Load rental
  useEffect(() => {
    setLoading(true);
    setError(null);
    fetchRental(id)
      .then((data) => {
        setRental(data);
        // Load nearby properties in same postcode
        if (data.postcode) {
          searchRentals({ postcode: data.postcode, limit: 6 })
            .then((res) => {
              const all = res?.rentals || res?.data || res || [];
              setNearby(all.filter((r) => String(r.id) !== String(id)).slice(0, 5));
            })
            .catch(() => {});
        }
      })
      .catch((err) => setError(err.message || 'Failed to load property.'))
      .finally(() => setLoading(false));
  }, [id]);

  // Load user's rating for this property
  useEffect(() => {
    if (!user) return;
    setRatingLoading(true);
    fetchRatingForRental(id)
      .then((data) => {
        setMyRating(data?.rating || 0);
        setAvgRating(data?.average_rating ?? data?.avgRating ?? null);
      })
      .catch(() => {})
      .finally(() => setRatingLoading(false));
  }, [id, user]);

  const handleRate = useCallback(async (star) => {
    if (!user) {
      setRatingMsg('Please log in to rate properties.');
      return;
    }
    setRatingLoading(true);
    setRatingMsg('');
    try {
      const data = await postRating(id, star);
      setMyRating(star);
      setAvgRating(data?.average_rating ?? data?.avgRating ?? null);
      setRatingMsg('Rating saved!');
    } catch (err) {
      setRatingMsg(err.message || 'Failed to save rating.');
    } finally {
      setRatingLoading(false);
    }
  }, [id, user]);

  if (loading) return <LoadingState message="Loading property details…" />;
  if (error) return <ErrorState message={error} onRetry={() => window.location.reload()} />;
  if (!rental) return null;

  const lat = parseFloat(rental.latitude);
  const lng = parseFloat(rental.longitude);
  const hasCoords = !isNaN(lat) && !isNaN(lng);

  return (
    <div className="detail-page">
      {/* Breadcrumb */}
      <div className="container">
        <nav className="breadcrumb" aria-label="Breadcrumb">
          <button className="breadcrumb__link" onClick={() => navigate(-1)}>← Back</button>
          <span className="breadcrumb__sep">/</span>
          <button className="breadcrumb__link" onClick={() => navigate('/search')}>Search</button>
          <span className="breadcrumb__sep">/</span>
          <span className="breadcrumb__current">{rental.address || `Property #${id}`}</span>
        </nav>
      </div>

      <div className="detail-page__grid container">
        {/* Left: info */}
        <div className="detail-page__info">
          <div className="detail-page__header">
            <div>
              <span className="badge badge--lg">{rental.property_type}</span>
              <h1 className="detail-page__title">{rental.address}</h1>
              <p className="detail-page__location">
                {rental.suburb}, {rental.state} {rental.postcode}
              </p>
            </div>
            <div className="detail-page__price">{formatPrice(rental.price)}</div>
          </div>

          {/* Key stats */}
          <div className="detail-stats">
            {rental.bedrooms != null && (
              <div className="detail-stat">
                <span className="detail-stat__icon">🛏</span>
                <span className="detail-stat__val">{rental.bedrooms}</span>
                <span className="detail-stat__label">Bedrooms</span>
              </div>
            )}
            {rental.bathrooms != null && (
              <div className="detail-stat">
                <span className="detail-stat__icon">🚿</span>
                <span className="detail-stat__val">{rental.bathrooms}</span>
                <span className="detail-stat__label">Bathrooms</span>
              </div>
            )}
            {rental.parking_spaces != null && (
              <div className="detail-stat">
                <span className="detail-stat__icon">🚗</span>
                <span className="detail-stat__val">{rental.parking_spaces}</span>
                <span className="detail-stat__label">Parking</span>
              </div>
            )}
            {rental.land_size != null && (
              <div className="detail-stat">
                <span className="detail-stat__icon">📐</span>
                <span className="detail-stat__val">{rental.land_size}</span>
                <span className="detail-stat__label">Land m²</span>
              </div>
            )}
          </div>

          {/* Details */}
          <div className="detail-card">
            <h2 className="detail-card__title">Property Details</h2>
            <DetailRow label="Property ID" value={rental.id} />
            <DetailRow label="Bond" value={rental.bond ? `$${Number(rental.bond).toLocaleString('en-AU')}` : null} />
            <DetailRow label="Available" value={rental.available_date} />
            <DetailRow label="Furnished" value={rental.furnished != null ? (rental.furnished ? 'Yes' : 'No') : null} />
            <DetailRow label="Pets Allowed" value={rental.pets_allowed != null ? (rental.pets_allowed ? 'Yes' : 'No') : null} />
            <DetailRow label="Description" value={rental.description} />
          </div>

          {/* Rating */}
          <div className="detail-card">
            <h2 className="detail-card__title">Ratings</h2>

            {avgRating != null && (
              <div className="rating-avg">
                <StarRating value={Math.round(avgRating)} readonly size="lg" />
                <span className="rating-avg__text">
                  Average: {Number(avgRating).toFixed(1)} / 5
                </span>
              </div>
            )}

            {user ? (
              <div className="rating-user">
                <p className="rating-user__label">
                  {myRating ? `Your rating: ${myRating} / 5` : 'Rate this property:'}
                </p>
                {ratingLoading ? (
                  <p>Saving…</p>
                ) : (
                  <StarRating value={myRating} onChange={handleRate} size="lg" />
                )}
                {ratingMsg && (
                  <p className={`rating-msg${ratingMsg === 'Rating saved!' ? ' rating-msg--success' : ' rating-msg--error'}`}>
                    {ratingMsg}
                  </p>
                )}
              </div>
            ) : (
              <p className="rating-user__label">
                <button className="btn btn--link" onClick={() => navigate('/login')}>Log in</button> to rate this property.
              </p>
            )}
          </div>
        </div>

        {/* Right: map + nearby */}
        <div className="detail-page__map-col">
          {hasCoords ? (
            <div className="map-wrapper">
              <h2 className="map-wrapper__title">Location</h2>
              <div className="map-container">
                <Map
                  height={380}
                  center={[lat, lng]}
                  zoom={14}
                  attribution={false}
                >
                  <Marker anchor={[lat, lng]} color="#e63946" width={40} />
                  {nearby.map((n) => {
                    const nLat = parseFloat(n.latitude);
                    const nLng = parseFloat(n.longitude);
                    if (isNaN(nLat) || isNaN(nLng)) return null;
                    return (
                      <Marker
                        key={n.id}
                        anchor={[nLat, nLng]}
                        color="#457b9d"
                        width={30}
                        onClick={() => navigate(`/rental/${n.id}`)}
                      />
                    );
                  })}
                </Map>
              </div>
              <p className="map-wrapper__hint">
                📍 {rental.suburb}, {rental.state} {rental.postcode}
              </p>
            </div>
          ) : (
            <div className="map-placeholder">
              <span>📍 Map not available for this property</span>
            </div>
          )}

          {/* Nearby */}
          {nearby.length > 0 && (
            <div className="nearby-section">
              <h3 className="nearby-section__title">Nearby in {rental.postcode}</h3>
              <ul className="nearby-list">
                {nearby.map((n) => (
                  <li key={n.id} className="nearby-item">
                    <button
                      className="nearby-item__btn"
                      onClick={() => navigate(`/rental/${n.id}`)}
                    >
                      <span className="nearby-item__address">{n.address || `Property #${n.id}`}</span>
                      <span className="nearby-item__price">{formatPrice(n.price)}</span>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RentalDetailPage;
